import os
import torch
import torchvision
from torchvision import models, transforms
import pandas as pd
from sklearn.model_selection import train_test_split
from torch.utils.data import Dataset, DataLoader
from PIL import Image

def download_model(url):
    model_state_dict = torch.load(url, map_location='cpu')['model_state_dict']
    model = models.__dict__['resnet18'](pretrained=False)
    model.load_state_dict(model_state_dict)

    return model

class CustomDataset(Dataset):
    def __init__(self, data_dir, labels_df, transform=None):
        self.data_dir = data_dir
        self.labels_df = labels_df
        self.transform = transform
        self.images = os.listdir(data_dir)
        
    def __len__(self):
        return len(self.images)

    def __getitem__(self, idx):
        image_path = os.path.join(self.data_dir, self.images[idx])
        label = self.labels_df.loc[self.labels_df['image'] == image_path, 'label'].values[0]
        
        image = Image.open(image_path)
        if self.transform is not None:
            image = self.transform(image)

        return {
            'image': image,
            'label': torch.tensor(label)
        }

def fine_tune_model(model, data_dir, labels_df, batch_size):
    train_transforms = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])

    val_transforms = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])

    dataset = CustomDataset(data_dir, labels_df, transform=train_transforms)
    train_loader = DataLoader(dataset, batch_size=batch_size, shuffle=True)

    dataset_val = CustomDataset(data_dir, labels_df, transform=val_transforms)
    val_loader = DataLoader(dataset_val, batch_size=batch_size, shuffle=False)

    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=0.001)

    for epoch in range(5):
        model.train()
        total_loss = 0
        for batch in train_loader:
            images, labels = batch['image'], batch['label']
            outputs = model(images)
            loss = criterion(outputs, labels)
            optimizer.zero_grad()
            loss.backward()
            optimizer.step()
            total_loss += loss.item()

        model.eval()
        with torch.no_grad():
            correct = 0
            for batch in val_loader:
                images, _ = batch['image'], batch['label']
                outputs = model(images)
                _, predicted = torch.max(outputs, dim=1)
                correct += (predicted == labels).sum().item()

        accuracy = correct / len(labels_df)
        print(f'Epoch: {epoch+1}, Loss: {total_loss/len(train_loader)}, Accuracy: {accuracy:.4f}')

if __name__ == '__main__':
    url = 'https://example.com/model_state_dict.pth'
    model = download_model(url)

    data_dir = '/path/to/custom/dataset'
    labels_df = pd.read_csv('/path/to/labels.csv')
    batch_size = 32

    fine_tune_model(model, data_dir, labels_df, batch_size)